import heapq
from collections import Counter
def top_k_frequent(nums, k):
    freq = Counter(nums)
    heap = []
    for val, f in freq.items():
        if len(heap) < k:
            heapq.heappush(heap, (f, val))
        else:
            if f > heap[0][0]:
                heapq.heapreplace(heap, (f, val))
    return [val for _, val in heap]

